using json = nlohmann::json;
class AdminTool1 {
public:
    json getSystemInfo() { json i;i[std::string("version")]=std::string("8.2.0");i[std::string("tool")]=std::string("AdminTool1");i[std::string("timestamp")]=std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::system_clock::now().time_since_epoch()).count();return i; }
    json getHealthStatus() { json h;h[std::string("status")]=std::string("HEALTHY");h[std::string("uptime")]=uptime_.count();return h; }
    bool performAction(const std::string& action,const json& params) { spdlog::info(std::string("AdminTool1 performing: ")+action); if(action==std::string("restart")){ return true; } if(action==std::string("reload")){ return true; } if(action==std::string("backup")){ return true; } return false; }
    void addUptime(int64_t ms) { uptime_+=std::chrono::milliseconds(ms); }
private:
    std::chrono::milliseconds uptime_{0};
};
