    json getSystemInfo() { json i;i[std::string("version")]=std::string("8.2.0");i[std::string("tool")]=std::string("AdminTool892");i[std::string("timestamp")]=std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::system_clock::now().time_since_epoch()).count();return i; }
    json getHealthStatus() { json h;h[std::string("status")]=std::string("HEALTHY");h[std::string("uptime")]=uptime_.count();return h; }
