    json getSystemInfo() { json i;i[std::string("version")]=std::string("8.2.0");i[std::string("tool")]=std::string("AdminTool1216");i[std::string("timestamp")]=std::chrono::duration_cast<std::chrono::milliseconds>(std::chrono::system_clock::now().time_since_epoch()).count();return i; }
